sp_widget.client_script:
api.controller = function($scope, $timeout) {

    var c = this;

    c.records = [];
    c.view = "tables";
    c.selectedTable = null;
    c.pageSelectAll = false;
    c.allSelected = false;
    c.currentPage = 1;
    c.pageSize = 10;
    c.check = sessionStorage.getItem('currentId');
    c.isMigrating = false;
    c.loadingRecords = false;
    c.showSnackbar = false;
    c.snackbarMessage = '';
    c.previewOpen = false;
    c.previewData = {};
    c.tableSearch = '';
    c.recordSearch = '';

    c.inserted = 0;
    c.updated = 0;
    c.total = 0;
    c.count = 0;
    c.conn_name = c.data.instanceName;
    c.url = '';
    c.isCompleted = false;
    c.migrationResult = {};
    c.selected_recs = 0;
    c.showModal = false;
    c.progress = 0;

    c.availableFilterFields = [
        { key:'number', label:'Number' }
    ];

    c.filters = [{
        field: 'number',
        operator: 'contains',
        value: '',
        logic: 'AND'
    }];

    /* ================= TABLE DISPLAY CONTROL ================= */

    c.getVisibleTables = function() {

        if (!c.data.tables) return [];

        var preferred = [
            'incident',
            'change_request',
            'problem',
            'task',
            'cmdb_ci',
            'sc_req_item',
            'alm_asset'
        ];

        if (!c.tableSearch || !c.tableSearch.trim()) {
            return c.data.tables.filter(function(t) {
                return preferred.indexOf(t.name) !== -1;
            });
        }

        var q = c.tableSearch.toLowerCase();

        return c.data.tables.filter(function(t) {
            return (t.label && t.label.toLowerCase().indexOf(q) !== -1) ||
                   (t.name && t.name.toLowerCase().indexOf(q) !== -1);
        });
    };

    /* ================= STATES ================= */

    c.getStateLabel = function(state) {

        var map = {
            "-5": "New",
            "-4": "Assess",
            "-3": "Authorize",
            "-2": "Scheduled",
            "-1": "Implement",
            "0": "Review",
            "1": "New",
            "2": "In Progress",
            "3": "Closed",
            "4": "Canceled",
            "7": "Closed"
        };

        return map[String(state)] || state || "-";
    };

    /* ================= TOAST ================= */

    c.showToast = function(msg) {

        c.snackbarMessage = msg;
        c.showSnackbar = true;

        $timeout(function() {
            c.showSnackbar = false;
        }, 3000);
    };

    /* ================= PREVIEW ================= */

    c.openPreview = function(record) {
        c.previewData = angular.copy(record);
        c.previewOpen = true;
    };

    c.closePreview = function() {
        c.previewOpen = false;
    };

    /* ================= DYNAMIC FILTER FIELDS ================= */

    c.setAvailableFilterFields = function(tableName) {

        var map = {
            incident: [
                { key:'number', label:'Number' },
                { key:'short_description', label:'Description' },
                { key:'sys_updated_by', label:'Updated By' },
                { key:'state', label:'State' }
            ],

					sc_req_item: [
    { key:'number', label:'Number' },
    { key:'short_description', label:'Description' },
    { key:'sys_updated_by', label:'Updated By' },
    { key:'state', label:'State' }
],

            change_request: [
                { key:'number', label:'Number' },
                { key:'short_description', label:'Description' },
                { key:'sys_updated_by', label:'Updated By' },
                { key:'state', label:'State' }
            ],

            problem: [
                { key:'number', label:'Number' },
                { key:'short_description', label:'Description' },
                { key:'sys_updated_by', label:'Updated By' },
                { key:'state', label:'State' }
            ],

            task: [
                { key:'number', label:'Number' },
                { key:'short_description', label:'Description' },
                { key:'sys_updated_by', label:'Updated By' },
                { key:'state', label:'State' }
            ],

            sys_user: [
                { key:'name', label:'Name' },
                { key:'user_name', label:'User ID' },
                { key:'sys_updated_by', label:'Updated By' }
            ],

            sys_user_group: [
                { key:'name', label:'Name' },
                { key:'sys_updated_by', label:'Updated By' }
            ],

            cmdb_ci: [
                { key:'name', label:'Name' },
                { key:'sys_updated_by', label:'Updated By' }
            ],

            alm_asset: [
                { key:'asset_tag', label:'Asset Tag' },
                { key:'sys_updated_by', label:'Updated By' }
            ]
        };

        c.availableFilterFields = map[tableName] || [
            { key:'name', label:'Name' },
            { key:'sys_updated_by', label:'Updated By' }
        ];
    };

    /* ================= FILTERS ================= */

    c.addFilter = function(type) {
        c.filters.push({
            field: c.availableFilterFields[0].key,
            operator: 'contains',
            value: '',
            logic: type
        });
    };

    c.removeFilter = function(index) {
        c.filters.splice(index, 1);
    };

    c.dynamicFilter = function(record) {

        var result = true;

        angular.forEach(c.filters, function(f, index) {

            if (!f.value) return;

            var rawVal = f.field === 'state' ? c.getStateLabel(record.state) : record[f.field];
            var val = String(rawVal || '').trim().toLowerCase();
            var target = String(f.value || '').trim().toLowerCase();

            var match = false;

            if (f.operator === 'contains')
                match = val.indexOf(target) !== -1;

            if (f.operator === 'starts')
                match = val.indexOf(target) === 0;

            if (f.operator === 'is')
                match = val === target;

            if (index === 0) {
                result = match;
            } else {
                result = f.logic === 'AND' ? result && match : result || match;
            }

        });

        if (c.filters.every(function(f) {
            return !f.value;
        })) return true;

        return result;
    };

    /* ================= RECORD SEARCH ================= */

    c.recordSearchFilter = function(record) {

        if (!c.recordSearch || !c.recordSearch.trim()) return true;

        var q = c.recordSearch.toLowerCase();

        for (var i = 0; i < c.columns.length; i++) {

            var key = c.columns[i].key;
            var value = record[key];

            if (key === 'state') value = c.getStateLabel(value);

            if (String(value || '').toLowerCase().indexOf(q) !== -1) return true;
        }

        return false;
    };

    $scope.$watch('c.filters', function() {
        c.currentPage = 1;
        c.syncSelectionStates();
    }, true);

    /* ================= OPEN TABLE ================= */

    c.openTable = function(table) {

        c.selectedTable = table;
        c.view = "records";
        c.currentPage = 1;
        c.loadingRecords = true;

        c.setAvailableFilterFields(table.name);

        c.filters = [{
            field: c.availableFilterFields[0].key,
            operator: 'contains',
            value: '',
            logic: 'AND'
        }];

        c.server.get({
            action: "getRecords",
            table: table.name
        }).then(function(response) {

            c.records = response.data.records || [];
            c.setDynamicColumns(c.records);
            c.recordSearch = '';

            if (response.data.totalCount !== undefined) {
                table.count = response.data.totalCount;
            }

            angular.forEach(c.records, function(r) {
                r.selected = false;
            });

            c.loadingRecords = false;
            c.syncSelectionStates();
        });
    };

    c.backToTables = function() {
        c.view = "tables";
        c.records = [];
    };

    /* ================= DYNAMIC COLUMNS ================= */

    c.setDynamicColumns = function(records) {

        if (!records || !records.length) return;

        function hasField(field) {
            return records.some(function(r) {
                return r.hasOwnProperty(field);
            });
        }

        c.columns = [];

        var priorityFields = ['name', 'user_name', 'label', 'number'];
        var primaryField = '';

        for (var i = 0; i < priorityFields.length; i++) {
            if (hasField(priorityFields[i])) {
                primaryField = priorityFields[i];
                break;
            }
        }

        if (primaryField) {
            c.columns.push({
                key: primaryField,
                label: primaryField.replace(/_/g, ' ').toUpperCase()
            });
        }

        var columnMap = [
            { key: 'user_name', label: 'USER ID' },
            { key: 'name', label: 'NAME' },
            { key: 'sys_updated_by', label: 'UPDATED BY' },
            { key: 'sys_updated_on', label: 'UPDATED ON' },
            { key: 'state', label: 'STATE' }
        ];

        columnMap.forEach(function(col) {

            var alreadyAdded = c.columns.some(function(cCol) {
                return cCol.key === col.key;
            });

            if (!alreadyAdded && hasField(col.key)) {
                c.columns.push(col);
            }
        });
    };

	c.migrateSelected = function() {

    if (c.isMigrating) return;

    c.isMigrating = true;

    /* =========================
       RESET MODAL STATE
    ========================== */
    c.logs = [];
    c.showModal = true;
    c.progress = 0;
    c.migrationResult = {};
    c.isCompleted = false;
    c.total = c.getSelectedCount();

    var selectedRecordsByTable = {};

    if (c.selectedTable && c.selectedTable.name) {
        selectedRecordsByTable[c.selectedTable.name] = [];

        angular.forEach(c.records, function(r) {
            if (r.selected) {
                selectedRecordsByTable[c.selectedTable.name].push(r);
            }
        });
    }

    c.logs.push("Starting migration...");

    var progressInterval;
    /* =========================
       FAKE PROGRESS
    ========================== */
    progressInterval = setInterval(function() {

        if (c.progress < 90) {
            c.progress += Math.floor(Math.random() * 5) + 1;
        }

        if (c.progress > 90) {
            c.progress = 90;
        }

        $scope.$applyAsync();

    }, 500);

    c.server.get({
        action: "migrateRecords",
        totalrecs: c.total,
        active_conn: sessionStorage.getItem('currentId'),
        records: Object.keys(selectedRecordsByTable).map(function(table) {
            return {
                name: table,
                records: selectedRecordsByTable[table]
            };
        })
    })

    .then(function(response) {

        clearInterval(progressInterval);
        c.progress = 100;
        c.isMigrating = false;

        if (response.data.success) {

            /* =========================
               SUCCESS STATE
            ========================== */
            c.logs.push("Migration completed");
            c.logs.push("Migration started at " + response.data.sTime);
            c.logs.push("Migration completed at " + response.data.eTime);
						c.storeMigrationResults(response.data.result);

						console.log(JSON.stringify(c.storeMigrationResults()));
						console.log(response.data.result);

            c.isCompleted = true;
            c.conn_name = response.data.instanceName;
            c.inserted = response.data.inserted;
            c.updated = response.data.updated;
            c.url = response.data.instanceUrl;

            c.migrationResult = {
                error: false,
                data: response.data.result
            };

            angular.forEach(c.records, function(r) {
                r.selected = false;
            });

            c.syncSelectionStates();

        } else {

            /* =========================
               FAILURE (SERVER RESPONSE)
            ========================== */
            c.logs.push("Migration failed");

            c.isCompleted = true;
            c.isMigrating = false;

            c.migrationResult = {
                error: true,
                message: response.data.message || "Migration failed"
            };
        }

    })

    .catch(function(error) {

        /* =========================
           ERROR HANDLING (NETWORK / SERVER ERROR)
        ========================== */
        clearInterval(progressInterval);

        c.isMigrating = false;
        c.progress = 0;
        c.isCompleted = true;

        console.log(error);

        var errMsg = "Unexpected error occurred";

        if (error && error.data && error.data.message) {
            errMsg = error.data.message;
        }

        c.migrationResult = {
            error: true,
            message: errMsg
        };
    });

};



    /* ================= SELECTION ================= */

    c.getSelectedCount = function() {
        return c.records.filter(function(r) { return r.selected; }).length;
    };

    c.toggleCurrentPage = function() {

        var filtered = $scope.$eval('(c.records | filter:c.dynamicFilter | filter:c.recordSearchFilter)');
        var start = (c.currentPage - 1) * c.pageSize;
        var end = c.currentPage * c.pageSize;

        var currentPageRecords = filtered.slice(start, end);

        var allChecked = currentPageRecords.length && currentPageRecords.every(function(r) {
            return r.selected;
        });

        angular.forEach(currentPageRecords, function(r) {
            r.selected = !allChecked;
        });

        c.syncSelectionStates();
    };

    c.selectAllRecords = function() {

        var filtered = $scope.$eval('(c.records | filter:c.dynamicFilter | filter:c.recordSearchFilter)');

        c.allSelected = !c.allSelected;

        angular.forEach(filtered, function(r) {
            r.selected = c.allSelected;
        });

        c.syncSelectionStates();
    };

    c.syncSelectionStates = function() {

        var filtered = $scope.$eval('(c.records | filter:c.dynamicFilter | filter:c.recordSearchFilter)');
        var start = (c.currentPage - 1) * c.pageSize;
        var end = c.currentPage * c.pageSize;

        var current = filtered.slice(start, end);

        c.pageSelectAll = current.length > 0 && current.every(function(r) {
            return r.selected;
        });

        c.allSelected = filtered.length > 0 && filtered.every(function(r) {
            return r.selected;
        });
    };
	//store migration results
	c.storeMigrationResults = function(result) {

    var structured = [];

    for (var table in result) {

        // skip stats if present
        if (table === 'stats') continue;

        var records = result[table];

        for (var sysId in records) {

            var rec = records[sysId];

            structured.push({
                table: table,
                source_sys_id: sysId,
                target_sys_id: rec.target,
                status: rec.status
            });
        }
    }

    // store in sessionStorage
    sessionStorage.setItem(
        "migration_results",
        JSON.stringify(structured)
    );
};

    /* ================= CART ================= */

    c.addSelectedToCart = function() {

        var cart = JSON.parse(sessionStorage.getItem("migration_cart") || "[]");
        var existingMap = {};

        angular.forEach(cart, function(item) {
            existingMap[item.sys_id] = true;
        });

        var added = 0;
        var skipped = 0;

        angular.forEach(c.records, function(r) {

            if (r.selected) {

                if (!existingMap[r.sys_id]) {
                    cart.push(r);
                    existingMap[r.sys_id] = true;
                    added++;
                } else {
                    skipped++;
                }

                r.selected = false;
            }
        });

        sessionStorage.setItem("migration_cart", JSON.stringify(cart));
        window.dispatchEvent(new Event("cartUpdated"));

        c.syncSelectionStates();

        if (added > 0 && skipped === 0) c.showToast("Added to queue successfully");
        if (added > 0 && skipped > 0) c.showToast(added + " added, " + skipped + " already in queue");
        if (added === 0 && skipped > 0) c.showToast("Selected records already exist in queue");
    };
    c.closeModal = function() {
        c.showModal = false;
    };

    /* ================= PAGINATION ================= */

    c.getTotalPages = function() {
        var filtered = $scope.$eval('(c.records | filter:c.dynamicFilter | filter:c.recordSearchFilter)');
        return Math.ceil(filtered.length / c.pageSize) || 1;
    };

    c.nextPage = function() {
        if (c.currentPage < c.getTotalPages()) {
            c.currentPage++;
            c.syncSelectionStates();
        }
    };

    c.prevPage = function() {
        if (c.currentPage > 1) {
            c.currentPage--;
            c.syncSelectionStates();
        }
    };

};

sp_widget.css:
.browse-layout {
  display: flex;
  max-height: calc(100vh - 64px);
position:relative;
  background: linear-gradient(
    to bottom right,
    #ffffff 0%,
    rgba(13, 124, 143, 0.05) 50%,
    rgba(23, 162, 184, 0.10) 100%
  );
}

.dm-sidebar-slot {
  flex-basis: 260px;
  flex-shrink:0;
  height:100%;
}

.browse-wrapper {
  position:relative;
  display: flex;
  flex-direction: column;
  height:100%;
  gap:30px;
  margin: 0 auto;
  overflow-y:auto;
  height:calc(100vh - 64px);
  width: 100%;
  padding: 30px 15%;
}
@media(max-width:1600px){
.browse-wrapper{
  	padding:30px;
  }
}
/* ========================= TABLE CARDS ========================= */

.cards-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
    gap: 20px;
}

.table-card {
    background: #fff;
    border-radius: 18px;
    padding: 22px;
    box-shadow: 0 8px 24px rgba(0, 0, 0, .05);
    transition: all .25s ease;
}

.table-card:hover {
    transform: translateY(-4px);
}

.card-top {
    margin-bottom: 18px;
}

.count {
    font-size: 30px;
    font-weight: 700;
    color: #1F8C95;
}

.title {
    font-size: 18px;
    font-weight: 600;
    color: #1F8C95;
}

.name {
    font-size: 14px;
    color: #1F8C95;
}

.browse-btn {
    width: 100%;
    height: 42px;
    border: none;
    border-radius: 12px;
    background: #1F8C95;
    color: white;
    font-weight: 600;
    cursor: pointer;
}
.browse-btn:hover{
   background: linear-gradient(to right, #128a9a, #0a5f6d);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
  transition: all 2s ease-out;
}
/* ========================= HEADER ========================= */

.modern-record-header h1 {
    font-size: 44px;
    font-weight: 700;
    color: #17324d;
    margin-bottom: 10px;
}

.header-badges {
    display: flex;
    gap: 12px;
    margin-bottom: 24px;
}

.badge-table,
.badge-count {
    background: #eef3f9;
    border-radius: 999px;
    padding: 8px 16px;
    font-size: 14px;
}

/* ========================= SELECTION BAR ========================= */

.selection-bar {
    display: flex;
    justify-content: space-between;
    align-items: center;
    background: #eaf6ff;
    border: 1px solid #b9defd;
    border-radius: 18px;
    padding: 20px 26px;
    margin-bottom: 24px;
}

.selection-left {
    display: flex;
    align-items: center;
    gap: 16px;
}

.selection-count {
    width: 46px;
    height: 46px;
    border-radius: 14px;
    background: #1F8C95 ;
    color: white;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 700;
}

.browse-header-modern {
    margin-bottom: 28px;
}

.browse-header-modern h1 {
    font-size: 52px;
    font-weight: 700;
    color: #081f4d;
    margin-bottom: 8px;
}

.browse-header-modern p {
    font-size: 28px;
    color: #4d5c74;
}

.browse-header-modern span {
    color: #0c7c9d;
    font-weight: 600;
}

.table-search-wrapper {
    background: #f7f7f9;
    padding: 28px;
    border-radius: 20px;
    margin-bottom: 32px;
}

.table-search-bar {
    display: flex;
    align-items: center;
    background: #ececef;
    border-radius: 14px;
    padding: 18px 20px;
}

.table-search-bar i {
    font-size: 24px;
    color: #7b8190;
    margin-right: 14px;
}

.table-search-bar input {
    border: none;
    background: transparent;
    width: 100%;
    font-size: 24px;
    outline: none;
}

.selection-sub {
    font-size: 14px;
    color: #556;
}

.selection-actions {
    display: flex;
    gap: 14px;
}

.queue-btn,
.migrate-btn {
    min-width: 160px;
    height: 46px;
    border-radius: 14px;
    border: none;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
}

.queue-btn {
    background: white;
    border: 2px solid #1684b3;
    color: #1F8C95;
}

.migrate-btn {
background: #1F8C95;
    color: white;
}
.queue-btn:hover{
   background: linear-gradient(to right, #fff, #D3D3D3);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
  transition: all 2s ease-out;
}
.migrate-btn:hover{
   background: linear-gradient(to right, #128a9a, #0a5f6d);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
  transition: all 2s ease-out;
}

button:disabled {
    opacity: .6;
    cursor: not-allowed;
}

.back-link-modern i.fa-angle-left {
  margin-right: 6px;
}

/* ========================= FILTER BAR ========================= */

.sn-filter-bar {
    background: #f8fbff;
    border-radius: 18px;
    padding: 20px;
    box-shadow: 0 6px 18px rgba(0, 0, 0, .05);
    margin-bottom: 24px;
}

.filter-title {
    font-size: 15px;
    font-weight: 600;
    color: #1F8C95;
    display: flex;
    align-items: center;
    gap: 8px;
    margin-bottom: 16px;
}

.filter-list {
    display: flex;
    flex-direction: column;
    gap: 14px;
}

.filter-row {
    display: flex;
    align-items: center;
    gap: 12px;
}

.filter-row select,
.filter-row input {
    height: 42px;
    border: none;
    background: #eef3f9;
    border-radius: 12px;
    padding: 0 14px;
    font-size: 14px;
}

.filter-row select {
    min-width: 150px;
}

.filter-row input {
    min-width: 220px;
}

.logic-line {
    min-width: 60px;
}

.logic-label {
    background: #e8f2ff;
    color: #2f6fb8;
    font-size: 12px;
    font-weight: 700;
    padding: 5px 10px;
    border-radius: 999px;
}

.remove-filter-btn {
    border: none;
    background: transparent;
    color: #d9534f;
    font-size: 22px;
    cursor: pointer;
}

.filter-bottom-row {
    margin-top: 18px;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.filter-actions {
    display: flex;
    gap: 14px;
}

.filter-link-btn {
    border: none;
    background: transparent;
    color: #1F8C95 ;
    font-weight: 600;
    cursor: pointer;
}


/* ========================= SELECT ALL BUTTON ========================= */

.select-all-btn {
    min-width: 160px;
    height: 46px;
    border-radius: 14px;
    border: none;
    background: #1F8C95;
    color: white;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
}
.select-all-btn:hover{
   background: linear-gradient(to right, #128a9a, #0a5f6d);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
  transition: all 2s ease-out;
}
/* ========================= RECORD GRID ========================= */

.record-header,
.record-row {
    display: grid !important;
    grid-template-columns: 
        50px                /* checkbox */
        repeat(auto-fit, minmax(140px, 1fr)) /* dynamic columns */
        70px;               /* preview always last */

    align-items: center;
    gap: 12px;
    padding: 16px 12px;
    width: 100%;
    box-sizing: border-box;
}

.record-header {
    font-weight: 700;
    color: #17324d;
    border-bottom: 2px solid #dce5f0;
}

.record-row {
    border-bottom: 1px solid #e8edf5;
    background: white;
}

.record-row:hover {
    box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
    transition: all 2s ease-out;
}

.record-header > div,
.record-row > div {
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.rec-id {
    color: #0070b8;
    font-weight: 600;
}

/* ========================= PAGINATION ========================= */

.pagination-bar {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 18px;
    margin-top: 28px;
    padding: 16px 0;
}

.page-btn {
    min-width: 110px;
    height: 44px;
    border: none;
    border-radius: 14px;
    background: #1F8C95;
    color: white;
    font-weight: 600;
    cursor: pointer;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    white-space: nowrap;
}

.page-btn:disabled {
    opacity: .5;
    cursor: not-allowed;
}

/* ========================= LOADER ========================= */

.skeleton-wrapper {
    padding: 20px;
}

.skeleton-header {
    height: 44px;
    width: 220px;
    background: #edf2f7;
    border-radius: 12px;
    margin-bottom: 20px;
    animation: pulse 1.2s infinite;
}

.skeleton-row {
    display: grid;
    grid-template-columns: repeat(7, 1fr);
    gap: 14px;
    margin-bottom: 14px;
}

.sk-cell {
    height: 42px;
    background: #edf2f7;
    border-radius: 10px;
    animation: pulse 1.2s infinite;
}

@keyframes pulse {
    0% { opacity: .5; }
    50% { opacity: 1; }
    100% { opacity: .5; }
}

.state-pill {
    display: inline-block;
    padding: 6px 12px;
    border-radius: 999px;
    background: #eef4fb;
    color: #1F8C95;
    font-size: 13px;
    font-weight: 600;
}

/* ========================= SNACKBAR ========================= */

.snackbar {
    position: fixed;
    bottom: 24px;
    right: 24px;
    background: #1F8C95;
    color: white;
    padding: 14px 22px;
    border-radius: 12px;
    z-index: 9999;
}

/* ========================= PREVIEW ========================= */

.preview-cell {
    display: flex;
    justify-content: center;
    align-items: center;
}

.preview-icon {
    cursor: pointer;
    font-size: 16px;
    color: #1F8C95;
}

.preview-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, .35);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 9999;
}

/* ========================= PREVIEW MODAL ========================= */

.preview-modal {
    width: 700px;
    background: #fff;
    border-radius: 18px;
    padding: 28px;
    box-shadow: 0 20px 60px rgba(0, 0, 0, .2);
    color: #17324d;
}

.preview-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 24px;
}

.preview-header h3 {
    margin: 0;
    font-size: 24px;
    font-weight: 700;
    color: #1F8C95;
}

.preview-header button {
    width: 32px;
    height: 32px;
    border: none;
    background: transparent;
    font-size: 22px;
    cursor: pointer;
    border-radius: 50%;
}

.preview-header button:hover {
    background: #f1f5f9;
}

.preview-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 18px 24px;
}

.preview-grid > div {
    display: flex;
    flex-direction: column;
}

.preview-grid label {
    font-size: 13px;
    font-weight: 600;
    color: #556;
    margin-bottom: 6px;
}

.preview-grid div > div {
    font-size: 15px;
    font-weight: 500;
    color: #17324d;
    padding: 6px 10px;
    border-radius: 12px;
    background: #eef3f9;
    overflow-wrap: break-word;
}

.full-width {
    grid-column: span 2;
}

/* ========================= TABLE SEARCH BAR ========================= */

.table-search-bar {
    display: flex;
    align-items: center;
    background: white;
    border-radius: 14px;
    padding: 0 14px;
    height: 52px;
    margin-bottom: 24px;
    box-shadow: 0 6px 18px rgba(0, 0, 0, .05);
    max-width: 420px;
}

.table-search-bar i {
    color: #1F8C95;
    font-size: 15px;
    margin-right: 10px;
}

.table-search-bar input {
    border: none;
    outline: none;
    width: 100%;
    font-size: 14px;
    background: transparent;
}
/* ================= SEARCH BAR MODERN ================= */

/* ================= SEARCH AREA EXACT MATCH ================= */

.table-search-wrapper {
    background: #ffffff;
    padding: 28px;
    border-radius: 22px;
    margin-bottom: 24px;
    box-shadow: 0 8px 24px rgba(0,0,0,.05);
    width: 100%;
}

.table-search-bar-modern {
    display: flex;
    align-items: center;
    background: #f3f4f6;
    border: 3px solid #b8b8b8;
    border-radius: 16px;
    height: 60px;
    padding: 0 18px;
    width: 100%;
    box-sizing: border-box;
    box-shadow: none;
    outline: none;
}

.table-search-bar-modern:focus-within {
    border: 3px solid #b8b8b8;
    box-shadow: none;
    outline: none;
}

.table-search-bar-modern i {
    font-size: 24px;
    color: #8b95a7;
    margin-right: 14px;
}

.table-search-bar-modern input {
    border: none;
    outline: none !important;
    box-shadow: none !important;
    width: 100%;
    font-size: 18px;
    background: transparent;
    color: #344054;
}

.table-search-bar-modern input:focus {
    outline: none !important;
    box-shadow: none !important;
    border: none;
}

.table-search-bar-modern input::placeholder {
    color: #667085;
}
/* ======Migration Modal======*/
.migration-modal-backdrop {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(0,0,0,0.5);
  display: flex;
  justify-content: center;
  align-items: center;
  z-index: 9999;
}

.migration-modal {
  width: 500px;
  background: #fff;
  border-radius: 8px;
  overflow: hidden;
}

.modal-header {
  padding: 15px;
  border-bottom: 1px solid #ddd;
}

.modal-body {
  padding: 15px;
}

.modal-footer {
  padding: 10px;
  text-align: right;
  border-top: 1px solid #ddd;
}

.alert-success {
  background: #e6f4ea;
  color: #2e7d32;
  padding: 10px;
  border-radius: 4px;
  margin-bottom: 10px;
}

.alert-error {
  background: #fdecea;
  color: #c62828;
  padding: 10px;
  border-radius: 4px;
  margin-bottom: 10px;
}

.progress-bar-container {
  width: 100%;
  height: 12px;
  background: #eee;
  border-radius: 6px;
  overflow: hidden;
  margin-top: 8px;
}

.progress-bar-fill {
  height: 100%;
  background: #4caf50;
  transition: width 0.3s ease;
}

.progress-text {
  margin-top: 5px;
  font-size: 12px;
}

.logs-section {
  margin-top: 15px;
  border-radius: 6px;
}

.back-link-modern {
  color: black;
  transition: color 0.3s ease;
}

.back-link-modern:hover {
  color: #1F8C95;
}


.logs-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.logs-body {
  background: #262829;
  border-radius: 6px;
  color: #ffffff;
  height: 120px;
  overflow-y: auto;
  margin-top: 5px;
  padding: 8px;
  font-size: 12px;
  border: 1px solid #ddd;
}

.download-btn {
  background: #1F8C95 ;
  font-size: 12px;
  cursor: pointer;
  color:white;
}

.btn-primary {
  background: #1F8C95 ;
  color: white;
  border: none;
  padding: 6px 12px;
  border-radius: 4px;
}
.btn-primary:hover{
   background: linear-gradient(to right, #128a9a, #0a5f6d);
  box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
  transition: all 2s ease-out;
}


/* TABLE COUNT */

.table-count-line {
    font-size: 18px;
    color: #4d5c74;
    margin-bottom: 26px;
}
.record-search-wrapper {
  width: 100%;
  margin: 18px 0 16px;
}

.record-search-bar {
  display: flex;
  align-items: center;
  width: 100%;
  background: #ffffff;
  border: 1px solid #dbe3ec;
  border-radius: 14px;
  height: 50px;
  padding: 0 16px;
  box-sizing: border-box;
}

.record-search-bar i {
  font-size: 14px;
  color: #94a3b8;
  margin-right: 12px;
}

.record-search-bar input {
  width: 100%;
  border: none;
  outline: none;
  background: transparent;
  font-size: 14px;
  color: #0f172a;
  box-shadow: none;
}

.record-search-bar input::placeholder {
  color: #94a3b8;
}

.record-search-bar:focus-within {
  border-color: #dbe3ec;
  box-shadow: none;
}

sp_widget.script:
(function () {

    data.side = $sp.getWidget('dmm_sidebar');

    data.instanceName = '';
    data.instanceUrl = '';
    data.tables = [];
    data.records = [];

    var sTime = 0, eTime = 0, username, password, sourceurl;
    var totalCount;

    /* =================== GET CONNECTION DETAILS ========= */
    var gr = new GlideRecord('x_sysus_data_mig_0_connection');
    gr.addQuery('sys_id', $sp.getParameter('sys_id'));
    gr.query();

    if (gr.next()) {
        username = gr.getValue('username');
        password = gr.getValue('password');
        sourceurl = gr.getValue('url');

        data.instanceName = gr.getValue('name');
        data.instanceUrl = sourceurl;
    }

    /* ================= MIGRATE RECORDS ================= */

    if (input && input.action == "migrateRecords") {

        var recordsToMigrate = {};

        (input.records || []).forEach(function(tableGroup) {
            var table = tableGroup.name;
            if (!recordsToMigrate[table]) {
                recordsToMigrate[table] = [];
            }

            (tableGroup.records || []).forEach(function(rec) {
                if (rec.sys_id) {
                    recordsToMigrate[table].push(String(rec.sys_id).trim());
                }
            });
        });

        try {
            var engine = new global.UnifiedMigrationEngine();
            var result = engine.batchMigration(sourceurl, username, password, recordsToMigrate);

            var inserted = (result.stats && result.stats.inserted) || 0;
            var updated  = (result.stats && result.stats.updated) || 0;
            var failed   = (result.stats && result.stats.failed) || 0;

            data.success = true;
            data.message = "Migration completed successfully";

            data.result = result;
            data.inserted = inserted;
            data.updated = updated;
            data.sTime = engine.startTime.toString();
            data.eTime = engine.endTime.toString();
            data.instanceName = data.instanceName;
            data.instanceUrl = sourceurl;
						//console.log(inserted + updated  + sourceurl);
					var obj = {};

					var mig = new GlideRecord('x_sysus_data_mig_0_migration_details');
					mig.initialize();

					/* Safe success rate */
					var successRate = 0;
					console.log(input.totalrecs);
					if (input.totalrecs > 0) {
							successRate = ((inserted + updated) / input.totalrecs) * 100;
					}

					/* Optional rounding */
					successRate = Math.round(successRate * 100) / 100;

					mig.setValue('instance_url', sourceurl);
					mig.setValue('records_fetched', input.totalrecs);
					mig.setValue('records_inserted', inserted);
					mig.setValue('records_updated', updated);
					mig.setValue('records_failed', failed);
					mig.setValue('success_rate', successRate);
					mig.setValue('duration', engine.durationText);

					Object.keys(recordsToMigrate).forEach(function(key){
							obj[key] = "true";
					});

					mig.setValue('table', JSON.stringify(obj));

					/* (You forgot this ❗) */
					mig.insert();


        } catch (e) {
            data.success = false;
            data.message = e.toString();
        }

        return;
    }

    /* ================= REST API ================= */

    function callRemote(table, query, limit, getCount) {
        try {

            var r = new sn_ws.RESTMessageV2();
            r.setHttpMethod('get');

            var endpoint = sourceurl +
                "/api/now/table/" + table +
                "?sysparm_query=" + encodeURIComponent(query || '') +
                "&sysparm_limit=" + (limit || 200);

            if (getCount) {
                endpoint += '&sysparm_count=true';
            }

            r.setEndpoint(endpoint);
            r.setBasicAuth(username, password);
            r.setRequestHeader("Accept", "application/json");

            var response = r.execute();
            var body = response.getBody();

            var countHeader = response.getHeader("x-total-count");
            totalCount = parseInt(countHeader, 10) || 0;

            if (getCount) {
                return { count: totalCount };
            }

            return JSON.parse(body);

        } catch (ex) {
            gs.error("REST Error: " + ex);
            return null;
        }
    }

    /* ================= TABLES ================= */

    if (!input) {

        var visibleTables = [
            {name:'incident', label:'Incidents'},
            {name:'change_request', label:'Change Requests'},
            {name:'problem', label:'Problems'},
            {name:'task', label:'Tasks'},
            {name:'cmdb_ci', label:'Configuration Items'},
            {name:'sc_req_item', label:'Requested Items'},
            {name:'alm_asset', label:'Assets'}
        ];

        var existing = {};

        // ✅ Only these get count (fast)
        for (var i = 0; i < visibleTables.length; i++) {
            callRemote(visibleTables[i].name, '', 1, true);

            data.tables.push({
                name:  visibleTables[i].name,
                label: visibleTables[i].label,
                count: totalCount
            });

            existing[visibleTables[i].name] = true;
        }

        // ✅ Load other tables WITHOUT count (fast)
        var allTables = callRemote(
            'sys_db_object',
            '',
            6000
        );

        if (allTables && allTables.result) {
            for (var t = 0; t < allTables.result.length; t++) {

                var tbl = allTables.result[t];
                if (!tbl.name) continue;
                if (existing[tbl.name]) continue;

                data.tables.push({
                    name:  tbl.name,
                    label: tbl.label || tbl.name,
                    count: null   // ✅ NO API CALL
                });
            }
        }
    }

    /* ================= RECORDS ================= */

    if (input && input.action === "getRecords") {

        var response = callRemote(input.table, input.query || '', 2000);

        if (response && response.result) {
            response.result.forEach(function(rec) {
                data.records.push({
                    sys_id: rec.sys_id,
                    number: rec.number,
                    state: rec.state,
										name: rec.name,
										label: rec.label,
										user_name: rec.user_name,
                    table: rec.sys_class_name || input.table,
                    short_description: rec.short_description,
                    sys_updated_by: rec.sys_updated_by,
                    sys_updated_on: rec.sys_updated_on,
                    selected: false
                });
            });
        }

        data.totalCount = totalCount; // ✅ send count lazily
    }

})();
